import { useEffect } from 'react';

/**
 * Хук проверки на клик снаружи календаря. Общий хук для всех календарей.
 */
const useOnOutsideCalendarClick = ({ calendarElement, datepickerElement, disabled, onOutsideClick, rootElement, }) => {
    useEffect(() => {
        if (disabled) {
            return;
        }
        const handleOutsideClick = (event) => {
            const targetElement = event?.target;
            const isOutsideClick = ![datepickerElement, calendarElement].some(element => element && element.contains(targetElement));
            if (isOutsideClick && onOutsideClick) {
                onOutsideClick();
            }
        };
        const listenerContainer = rootElement || globalThis;
        listenerContainer.addEventListener('mousedown', handleOutsideClick);
        return () => listenerContainer.removeEventListener('mousedown', handleOutsideClick);
    }, [calendarElement, datepickerElement, disabled, onOutsideClick, rootElement]);
};

export { useOnOutsideCalendarClick };
